-- yumyumyumi data export — extracted from Supabase cluster backup (01-10-2025)
-- Self-contained: schema + data for public.recipes, bookmarks, profiles
-- Drop-in for Postgres (Neon, etc.)

CREATE TABLE IF NOT EXISTS public.recipes (
    id uuid DEFAULT gen_random_uuid() NOT NULL PRIMARY KEY,
    user_id uuid,
    title text NOT NULL,
    summary text,
    tags text[],
    tips text,
    cook_time integer DEFAULT 0,
    servings integer DEFAULT 1,
    image_url text,
    source text,
    is_public boolean DEFAULT true,
    created_at timestamptz DEFAULT now(),
    updated_at timestamptz DEFAULT now(),
    ingredients jsonb DEFAULT '[]'::jsonb NOT NULL,
    directions jsonb DEFAULT '[]'::jsonb NOT NULL
);

CREATE TABLE IF NOT EXISTS public.profiles (
    id uuid NOT NULL PRIMARY KEY,
    username text, full_name text, avatar_url text,
    created_at timestamptz DEFAULT now(), updated_at timestamptz DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.bookmarks (
    id uuid DEFAULT gen_random_uuid() NOT NULL PRIMARY KEY,
    user_id uuid, recipe_id uuid, created_at timestamptz DEFAULT now()
);



